// Comparar version actual con la almacenada en static data
const staticData = $getWorkflowStaticData('global');
const input = $input.first().json;

// Detectar error HTTP en el nodo anterior
if (input.error || input.code) {
  return [{
    json: {
      status: 'error',
      errorMessage: input.message || input.error || 'Error al obtener latest_version.txt',
      latestVersion: null,
      oldVersion: staticData.lastVersion || null
    }
  }];
}

// La respuesta es texto plano, puede venir como string en data o body
const rawVersion = (typeof input === 'string' ? input : (input.data || input.body || '')).toString().trim();

if (!rawVersion || rawVersion.length === 0) {
  return [{
    json: {
      status: 'error',
      errorMessage: 'latest_version.txt esta vacio o no se pudo leer',
      latestVersion: null,
      oldVersion: staticData.lastVersion || null
    }
  }];
}

const latestVersion = rawVersion;
const storedVersion = staticData.lastVersion || null;

// Primera ejecucion: no hay version almacenada
if (!storedVersion) {
  staticData.lastVersion = latestVersion;
  return [{
    json: {
      status: 'first_run',
      latestVersion: latestVersion,
      oldVersion: null,
      isNewVersion: false
    }
  }];
}

// Comparar versiones
const isNew = latestVersion !== storedVersion;

return [{
  json: {
    status: isNew ? 'new_version' : 'no_change',
    latestVersion: latestVersion,
    oldVersion: storedVersion,
    isNewVersion: isNew
  }
}];

// Comparar metricas entre version antigua y nueva, formatear mensaje Telegram
const staticData = $getWorkflowStaticData('global');

// Recuperar datos del nodo IF
const versionInfo = $('IF New Version').first().json;
const newVersion = versionInfo.latestVersion;
const oldVersion = versionInfo.oldVersion;

// Obtener metadata de ambas versiones
const allItems = $input.all();
const newMeta = allItems[0]?.json || {};
const oldMeta = allItems[1]?.json || {};

// Funcion auxiliar para extraer metricas de metadata.json
// Estructura esperada: { rf_val_f1, xgb_val_f1, train_samples, trained_at, ... }
function getMetric(meta, key, fallback) {
  if (!meta || meta.error || meta.code) return fallback;
  return meta[key] !== undefined ? meta[key] : fallback;
}

const newRfF1 = getMetric(newMeta, 'rf_val_f1', null);
const oldRfF1 = getMetric(oldMeta, 'rf_val_f1', null);
const newXgbF1 = getMetric(newMeta, 'xgb_val_f1', null);
const oldXgbF1 = getMetric(oldMeta, 'xgb_val_f1', null);
const newTrainSize = getMetric(newMeta, 'train_samples', null);
const oldTrainSize = getMetric(oldMeta, 'train_samples', null);
const newDate = getMetric(newMeta, 'trained_at', null);
const oldDate = getMetric(oldMeta, 'trained_at', null);

// Formatear valores para la tabla
function fmt(val, decimals) {
  if (val === null || val === undefined) return 'N/A';
  return typeof val === 'number' ? val.toFixed(decimals) : String(val);
}

function fmtDate(val) {
  if (!val) return 'N/A';
  // Tomar solo YYYY-MM-DD
  return String(val).substring(0, 10);
}

function fmtDiff(oldVal, newVal) {
  if (oldVal === null || newVal === null) return 'N/A';
  const diff = newVal - oldVal;
  const sign = diff >= 0 ? '+' : '';
  return sign + diff.toFixed(3);
}

// Clasificar resultado: MEJORA, DEGRADACION, LATERAL
// MEJORA = ambos F1 suben. DEGRADACION = alguno baja >2%. LATERAL = resto.
let resultado = '\u27a1\ufe0f LATERAL';
let resultadoEmoji = '\u27a1\ufe0f';

if (newRfF1 !== null && oldRfF1 !== null && newXgbF1 !== null && oldXgbF1 !== null) {
  const rfDiff = newRfF1 - oldRfF1;
  const xgbDiff = newXgbF1 - oldXgbF1;

  if (rfDiff > 0 && xgbDiff > 0) {
    resultado = '\ud83d\udcc8 MEJORA';
    resultadoEmoji = '\ud83d\udcc8';
  } else if (rfDiff < -0.02 || xgbDiff < -0.02) {
    resultado = '\ud83d\udcc9 DEGRADACION';
    resultadoEmoji = '\ud83d\udcc9';
  }
}

// Emojis para deltas individuales
function deltaEmoji(oldVal, newVal) {
  if (oldVal === null || newVal === null) return '\u2139\ufe0f';
  return newVal >= oldVal ? '\ud83d\udcc8' : '\ud83d\udcc9';
}

// Construir mensaje HTML
let msg = `<b>\ud83d\udd04 Retrain Completado \u2014 Trading Memes</b>\n\n`;
msg += `<b>Nueva versi\u00f3n:</b> ${newVersion}\n`;
msg += `<b>Anterior:</b> ${oldVersion}\n`;
msg += `<b>Resultado:</b> ${resultado}\n\n`;

msg += `<b>\ud83d\udcca Comparativa de M\u00e9tricas:</b>\n`;
msg += `<pre>`;
msg += `\u250c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u252c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u252c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2510\n`;
msg += `\u2502 M\u00e9trica       \u2502 Anterior \u2502 Nuevo    \u2502\n`;
msg += `\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u253c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u253c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2524\n`;
msg += `\u2502 RF F1         \u2502 ${fmt(oldRfF1, 3).padEnd(8)} \u2502 ${fmt(newRfF1, 3).padEnd(8)} \u2502\n`;
msg += `\u2502 XGB F1        \u2502 ${fmt(oldXgbF1, 3).padEnd(8)} \u2502 ${fmt(newXgbF1, 3).padEnd(8)} \u2502\n`;
msg += `\u2502 Tokens train  \u2502 ${fmt(oldTrainSize, 0).padEnd(8)} \u2502 ${fmt(newTrainSize, 0).padEnd(8)} \u2502\n`;
msg += `\u2502 Fecha         \u2502 ${fmtDate(oldDate).padEnd(8)} \u2502 ${fmtDate(newDate).padEnd(8)} \u2502\n`;
msg += `\u2514\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2534\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2518`;
msg += `</pre>\n\n`;

msg += `${deltaEmoji(oldRfF1, newRfF1)} Cambio F1 RF: ${fmtDiff(oldRfF1, newRfF1)}\n`;
msg += `${deltaEmoji(oldXgbF1, newXgbF1)} Cambio F1 XGB: ${fmtDiff(oldXgbF1, newXgbF1)}`;

// Actualizar static data con la nueva version
staticData.lastVersion = newVersion;

return [{
  json: {
    text: msg,
    chat_id: '1558705287'
  }
}];

// Rama sin cambios o primera ejecucion
const versionInfo = $('Check Version').first().json;
const status = versionInfo.status;
const version = versionInfo.latestVersion;

let msg;

if (status === 'error') {
  // Error al obtener version
  const errorDetail = versionInfo.errorMessage || 'Error desconocido';
  msg = `<b>\ud83d\udd04 Retrain Check \u2014 Trading Memes</b>\n`;
  msg += `\u274c ERROR: ${errorDetail}\n`;
  if (versionInfo.oldVersion) {
    msg += `\u00daltima versi\u00f3n conocida: ${versionInfo.oldVersion}`;
  }
} else if (status === 'first_run') {
  // Primera ejecucion, version inicializada
  msg = `<b>\ud83d\udd04 Retrain Check \u2014 Trading Memes</b>\n`;
  msg += `\u2139\ufe0f Retrain Notifier inicializado. Versi\u00f3n: ${version}`;
} else {
  // Sin cambios
  msg = `<b>\ud83d\udd04 Retrain Check \u2014 Trading Memes</b>\n`;
  msg += `\u2139\ufe0f Sin cambios. Modelo actual: ${version}`;
}

return [{
  json: {
    text: msg,
    chat_id: '1558705287'
  }
}];
